// ═══════════════════════════════════════════════════════════════════════════
// SQLite Schema
// ═══════════════════════════════════════════════════════════════════════════

const LONGITUDINAL_SCHEMA = `
CREATE TABLE IF NOT EXISTS longitudinal_sessions (
  runId                  TEXT PRIMARY KEY,
  batchId                TEXT NOT NULL,
  cohortSize             INTEGER NOT NULL,
  userId                 TEXT NOT NULL,
  role                   TEXT NOT NULL,
  scenarioId             TEXT NOT NULL,
  sessionIndex           INTEGER NOT NULL,
  timeHorizon            TEXT NOT NULL,
  surface                TEXT NOT NULL,
  toolCallCount          INTEGER NOT NULL DEFAULT 0,
  latencyMs              INTEGER NOT NULL DEFAULT 0,
  packetGenerated        INTEGER NOT NULL DEFAULT 0,
  packetReused           INTEGER NOT NULL DEFAULT 0,
  repeatQuestionDetected INTEGER NOT NULL DEFAULT 0,
  contextRestated        INTEGER NOT NULL DEFAULT 0,
  exportProduced         INTEGER NOT NULL DEFAULT 0,
  judgeScore             REAL NOT NULL DEFAULT 0,
  errors                 TEXT NOT NULL DEFAULT '[]',
  createdAt              TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS founder_packets (
  id          TEXT PRIMARY KEY,
  entityId    TEXT NOT NULL,
  scenarioId  TEXT NOT NULL,
  userId      TEXT NOT NULL,
  createdAt   TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS causal_events (
  id          TEXT PRIMARY KEY,
  userId      TEXT NOT NULL,
  eventType   TEXT NOT NULL,
  payload     TEXT NOT NULL DEFAULT '{}',
  createdAt   TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS session_actions (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  sessionRunId    TEXT NOT NULL,
  actionIndex     INTEGER NOT NULL,
  toolName        TEXT NOT NULL,
  inputSummary    TEXT NOT NULL DEFAULT '',
  outputSummary   TEXT NOT NULL DEFAULT '',
  latencyMs       INTEGER NOT NULL DEFAULT 0,
  passed          INTEGER NOT NULL DEFAULT 0,
  skipped         INTEGER NOT NULL DEFAULT 0,
  error           TEXT,
  createdAt       TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (sessionRunId) REFERENCES longitudinal_sessions(runId)
);

CREATE TABLE IF NOT EXISTS benchmark_rollups (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  period          TEXT NOT NULL,
  periodKey       TEXT NOT NULL,
  totalRuns       INTEGER NOT NULL DEFAULT 0,
  completionRate  REAL NOT NULL DEFAULT 0,
  avgJudgeScore   REAL NOT NULL DEFAULT 0,
  rca             REAL NOT NULL DEFAULT 0,
  prr             REAL NOT NULL DEFAULT 0,
  durabilityScore REAL NOT NULL DEFAULT 0,
  topFailureMode  TEXT NOT NULL DEFAULT 'none',
  createdAt       TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(period, periodKey)
);

CREATE TABLE IF NOT EXISTS workflow_maturity (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  scenarioId      TEXT NOT NULL,
  maturityLevel   TEXT NOT NULL,
  label           TEXT NOT NULL,
  evidence        TEXT NOT NULL DEFAULT '',
  batchId         TEXT NOT NULL,
  createdAt       TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(scenarioId, batchId)
);

CREATE INDEX IF NOT EXISTS idx_longitudinal_batch  ON longitudinal_sessions(batchId);
CREATE INDEX IF NOT EXISTS idx_longitudinal_user   ON longitudinal_sessions(userId);
CREATE INDEX IF NOT EXISTS idx_longitudinal_cohort ON longitudinal_sessions(cohortSize);
CREATE INDEX IF NOT EXISTS idx_founder_packets_entity ON founder_packets(entityId, scenarioId);
CREATE INDEX IF NOT EXISTS idx_causal_events_user ON causal_events(userId);
CREATE INDEX IF NOT EXISTS idx_session_actions_run ON session_actions(sessionRunId);
CREATE INDEX IF NOT EXISTS idx_benchmark_rollups_period ON benchmark_rollups(period, periodKey);
CREATE INDEX IF NOT EXISTS idx_workflow_maturity_scenario ON workflow_maturity(scenarioId);
`;

function ensureSchema(): void {
  const db = getDb();
  // Migrate: drop old founder_packets / causal_events if they exist without expected columns
  // (safe because these are benchmark-only tables, not user data)
  try {
    db.prepare("SELECT userId FROM founder_packets LIMIT 1").get();
  } catch {
    db.exec("DROP TABLE IF EXISTS founder_packets");
  }
  try {
    db.prepare("SELECT userId FROM causal_events LIMIT 1").get();
  } catch {
    db.exec("DROP TABLE IF EXISTS causal_events");
  }
  // Migrate session_actions if schema changed
  try {
    db.prepare("SELECT sessionRunId FROM session_actions LIMIT 1").get();
  } catch {
    db.exec("DROP TABLE IF EXISTS session_actions");
  }
  db.exec(LONGITUDINAL_SCHEMA);
}

// ═══════════════════════════════════════════════════════════════════════════
// Tool Assembly
// ═══════════════════════════════════════════════════════════════════════════

let _allTools: McpTool[] | null = null;

async function getAllTools(): Promise<McpTool[]> {
  if (_allTools) return _allTools;

  getDb();
  _setDbAccessor(getDb);

  const domainTools = await loadToolsets(ALL_DOMAIN_KEYS);
  const metaTools = createMetaTools(domainTools);
  const allToolsFlat = [
    ...domainTools,
    ...metaTools,
    ...deepSimTools,
    ...reconTools,
    ...founderTools,
    ...founderTrackingTools,
    ...dogfoodJudgeTools,
    ...learningTools,
    ...flywheelTools,
  ];
  const discoveryTools = createProgressiveDiscoveryTools(
    allToolsFlat.map((t) => ({ name: t.name, description: t.description })),
  );
  _allTools = [...allToolsFlat, ...discoveryTools];
  return _allTools;
}

// ═══════════════════════════════════════════════════════════════════════════
// Helpers
// ═══════════════════════════════════════════════════════════════════════════

function findTool(tools: McpTool[], name: string): McpTool | null {
  return tools.find((t) => t.name === name) ?? null;
}

async function callTool(
  tool: McpTool,
  args: Record<string, unknown> = {},
): Promise<{ ok: boolean; result: unknown; error?: string; ms: number }> {
  const start = Date.now();
  try {
    const result = await tool.handler(args);
    return { ok: true, result, ms: Date.now() - start };
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    return { ok: false, result: null, error: message, ms: Date.now() - start };
  }
}

function persistSession(session: SessionRun, batchId: string, cohortSize: number): void {
  const db = getDb();
  db.prepare(`
    INSERT OR REPLACE INTO longitudinal_sessions
      (runId, batchId, cohortSize, userId, role, scenarioId, sessionIndex,
       timeHorizon, surface, toolCallCount, latencyMs, packetGenerated,
       packetReused, repeatQuestionDetected, contextRestated, exportProduced,
       judgeScore, errors)
    VALUES
      (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(
    session.runId,
    batchId,
    cohortSize,
    session.userId,
    session.role,
    session.scenarioId,
    session.sessionIndex,
    session.timeHorizon,
    session.surface,
    session.toolCallCount,
    session.latencyMs,
    session.packetGenerated ? 1 : 0,
    session.packetReused ? 1 : 0,
    session.repeatQuestionDetected ? 1 : 0,
    session.contextRestated ? 1 : 0,
    session.exportProduced ? 1 : 0,
    session.judgeScore,
    JSON.stringify(session.errors),
  );
}

function persistActionRecords(sessionRunId: string, actions: ActionRecord[]): void {
  const db = getDb();
  const stmt = db.prepare(`
    INSERT INTO session_actions (sessionRunId, actionIndex, toolName, inputSummary, outputSummary, latencyMs, passed, skipped, error)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);
  for (const a of actions) {
    stmt.run(sessionRunId, a.actionIndex, a.toolName, a.inputSummary, a.outputSummary, a.latencyMs, a.passed ? 1 : 0, a.skipped ? 1 : 0, a.error ?? null);
  }
}

/**
 * Issue 1 fix: Check founder_packets table for a prior packet matching this entity+scenario.
 * Returns true only if sessionIndex > 1 AND a stored packet exists.
 */
function checkPriorPacket(db: ReturnType<typeof getDb>, entityId: string, _scenarioId: string, sessionIndex: number): boolean {
  if (sessionIndex <= 1) return false;
  // Reuse packet if ANY prior packet exists for this entity (cross-scenario reuse)
  const row = db.prepare(`
    SELECT COUNT(*) as c FROM founder_packets
    WHERE entityId = ?
  `).get(entityId) as { c: number } | undefined;
  return (row?.c ?? 0) > 0;
}

/**
 * Issue 1 fix: Store a new packet entry so future sessions can reuse it.
 */
function storePriorPacket(db: ReturnType<typeof getDb>, entityId: string, scenarioId: string, userId: string): void {
  // Only store if one doesn't already exist for this entity+scenario
  const existing = db.prepare(`
    SELECT COUNT(*) as c FROM founder_packets WHERE entityId = ? AND scenarioId = ?
  `).get(entityId, scenarioId) as { c: number } | undefined;
  if ((existing?.c ?? 0) === 0) {
    db.prepare(`
      INSERT INTO founder_packets (id, entityId, scenarioId, userId) VALUES (?, ?, ?, ?)
    `).run(genId("pkt"), entityId, scenarioId, userId);
  }
}

/**
 * Issue 2 fix: Check causal_events for prior context from this user.
 * If prior events exist, memory carries forward and context does NOT need restating.
 */
function hasCausalMemory(db: ReturnType<typeof getDb>, userId: string): boolean {
  const row = db.prepare(`
    SELECT COUNT(*) as c FROM causal_events WHERE userId = ?
  `).get(userId) as { c: number } | undefined;
  return (row?.c ?? 0) > 0;
}

/**
 * Issue 2 fix: Record a session-start causal event so future sessions find memory.
 */
function recordCausalEvent(db: ReturnType<typeof getDb>, userId: string, scenarioId: string, sessionIndex: number): void {
  db.prepare(`
    INSERT INTO causal_events (id, userId, eventType, payload) VALUES (?, ?, ?, ?)
  `).run(
    genId("ce"),
    userId,
    "session_start",
    JSON.stringify({ scenarioId, sessionIndex }),
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// Session Simulation
// ═══════════════════════════════════════════════════════════════════════════

async function simulateSession(
  user: CohortUser,
  scenarioId: string,
  sessionIndex: number,
  timeHorizon: SessionRun["timeHorizon"],
  batchId: string,
  cohortSize: number,
  perturbation?: Perturbation,
): Promise<SessionRun> {
  const tools = await getAllTools();
  const chain = SCENARIO_TOOL_CHAINS[scenarioId];
  if (!chain) {
    throw new Error(`Unknown scenario "${scenarioId}". Known: ${Object.keys(SCENARIO_TOOL_CHAINS).join(", ")}`);
  }

  const db = getDb();
  const runId = genId("lh");
  const sessionStart = Date.now();
  let toolCallCount = 0;
  const errors: string[] = [];
  let packetGenerated = false;
  let exportProduced = false;
  const entityId = "anthropic"; // normalized entity for this harness

  // Issue 3 fix: build set of available tool names for graceful skip
  const availableToolNames = new Set(tools.map((t) => t.name));

  // Issue 1 fix: check founder_packets for prior packet before running chain
  const priorPacketExists = checkPriorPacket(db, entityId, scenarioId, sessionIndex);
  const packetReused = priorPacketExists;

  // Issue 2 fix: check causal_events for prior memory from this user
  const hasPriorMemory = sessionIndex > 1 && hasCausalMemory(db, user.userId);
  // Context restated only if session > 1 AND no causal memory exists
  let contextRestated = sessionIndex > 1 && !hasPriorMemory;

  // Repeat question: if context was restated, the user likely re-asked old questions.
  let repeatQuestionDetected = contextRestated;

  // Issue 1 fix: if packet reused and sessionIndex > 1, skip regeneration of the chain
  // (but still run non-packet tools like record_event)
  const skipRegeneration = packetReused && sessionIndex > 1;
  let allToolsFound = true;

  // Per-action tracking
  const actionRecords: ActionRecord[] = [];

  // Apply thread_reset perturbation BEFORE chain (wipes causal memory)
  if (perturbation?.type === "thread_reset") {
    const db2 = getDb();
    db2.prepare("DELETE FROM causal_events WHERE userId = ?").run(user.userId);
  }

  // Apply stale_memory perturbation BEFORE chain (injects stale data)
  if (perturbation?.type === "stale_memory") {
    const db2 = getDb();
    const staleDate = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
    db2.prepare(`
      INSERT INTO causal_events (id, userId, eventType, payload, createdAt)
      VALUES (?, ?, ?, ?, ?)
    `).run(
      genId("ce_stale"),
      user.userId,
      "stale_injection",
      JSON.stringify({ entity: "StaleCorpXYZ", scenarioId: "stale_test", injected: true }),
      staleDate,
    );
  }

  // Determine which tools to "fail" for tool_failure perturbation
  const failedToolIndices = new Set<number>();
  if (perturbation?.type === "tool_failure") {
    const rng = seededRandom(sessionIndex * 17 + chain.length);
    const failCount = rng() > 0.5 ? 2 : 1;
    // Pick random non-first, non-last indices
    const candidates = chain.map((_, i) => i).filter((i) => i > 0 && i < chain.length - 1);
    for (let f = 0; f < Math.min(failCount, candidates.length); f++) {
      const pick = Math.floor(rng() * candidates.length);
      failedToolIndices.add(candidates[pick]);
      candidates.splice(pick, 1);
    }
  }

  // Determine if schema_change perturbation skips a field
  const schemaSkipExport = perturbation?.type === "schema_change";

  // Run the tool chain
  for (let i = 0; i < chain.length; i++) {
    const toolName = chain[i];
    const isCoreTool = i === 0; // first tool in chain is core

    // Issue 3 fix: check if tool exists in loaded tools before calling
    if (!availableToolNames.has(toolName)) {
      actionRecords.push({
        actionIndex: i, toolName, inputSummary: "", outputSummary: "",
        latencyMs: 0, passed: !isCoreTool, skipped: true, error: isCoreTool ? `tool_not_found:${toolName}` : undefined,
      });
      if (isCoreTool) {
        errors.push(`tool_not_found:${toolName}`);
        allToolsFound = false;
      }
      toolCallCount++;
      continue;
    }

    // Perturbation: injected tool failure
    if (failedToolIndices.has(i)) {
      const errMsg = `perturbation:tool_failure_injected:${toolName}`;
      errors.push(errMsg);
      actionRecords.push({
        actionIndex: i, toolName, inputSummary: "perturbation_injected", outputSummary: "",
        latencyMs: 0, passed: false, skipped: false, error: errMsg,
      });
      toolCallCount++;
      continue;
    }

    const tool = findTool(tools, toolName)!;

    // Issue 1 fix: skip memo/analysis tools if reusing prior packet
    if (skipRegeneration && toolName !== "record_event" && toolName !== "track_milestone" && toolName !== "check_mcp_setup") {
      toolCallCount++;
      const skipExport = toolName === "render_decision_memo";
      if (skipExport && !schemaSkipExport) {
        exportProduced = true;
      }
      actionRecords.push({
        actionIndex: i, toolName, inputSummary: "skip_reuse", outputSummary: "packet_reused",
        latencyMs: 0, passed: true, skipped: true,
      });
      continue;
    }

    // Build scenario-appropriate args
    const args = buildToolArgs(toolName, user, scenarioId);
    const result = await callTool(tool, args);
    toolCallCount++;

    actionRecords.push({
      actionIndex: i, toolName,
      inputSummary: JSON.stringify(args).slice(0, 200),
      outputSummary: result.ok ? String(result.result).slice(0, 200) : "",
      latencyMs: result.ms, passed: result.ok, skipped: false,
      error: result.ok ? undefined : result.error?.slice(0, 200),
    });

    if (!result.ok) {
      errors.push(`${toolName}:${result.error?.slice(0, 120)}`);
    }

    // Detect packet generation from memo/export tools
    if (toolName === "render_decision_memo" && result.ok) {
      packetGenerated = true;
      if (!schemaSkipExport) {
        exportProduced = true;
      }
    }
  }

  // Issue 1 fix: store packet after generation so future sessions can reuse
  if (packetGenerated && !priorPacketExists) {
    storePriorPacket(db, entityId, scenarioId, user.userId);
  }

  // Issue 2 fix: record causal event for every session so future sessions find memory
  recordCausalEvent(db, user.userId, scenarioId, sessionIndex);

  const latencyMs = Date.now() - sessionStart;

  // Dynamic judge scoring (replaces hardcoded 3.0 base)
  // Session 1: base 3.5, Session 2+: base 3.0
  let judgeScore = sessionIndex === 1 ? 3.5 : 3.0;
  // Session 2+ with packet reuse: +0.5
  if (sessionIndex > 1 && packetReused) judgeScore += 0.5;
  // Session 2+ without context restatement (memory carried forward): +0.5
  if (sessionIndex > 1 && !contextRestated) judgeScore += 0.5;
  // No errors: +0.5
  if (errors.length === 0) judgeScore += 0.5;
  // Tool chain complete (all tools found): +0.5
  if (allToolsFound) judgeScore += 0.5;
  judgeScore = Math.max(1.0, Math.min(5.0, judgeScore));

  // Pick a surface based on scenario
  const surface: SessionRun["surface"] = scenarioId === "memo_export"
    ? "local_dashboard"
    : scenarioId === "important_change"
      ? "engine_api"
      : "mcp";

  // Apply model_swap perturbation: jitter the judge score
  if (perturbation?.type === "model_swap") {
    const rng = seededRandom(sessionIndex * 31 + runId.length);
    const jitter = (rng() - 0.5) * 0.6; // -0.3 to +0.3
    judgeScore = Math.max(1.0, Math.min(5.0, judgeScore + jitter));
  }

  // Apply thread_reset perturbation: force context restated
  if (perturbation?.type === "thread_reset") {
    contextRestated = true;
    repeatQuestionDetected = true;
  }

  let session: SessionRun = {
    runId,
    userId: user.userId,
    role: user.role,
    scenarioId,
    sessionIndex,
    timeHorizon,
    surface,
    toolCallCount,
    latencyMs,
    packetGenerated,
    packetReused,
    repeatQuestionDetected,
    contextRestated,
    exportProduced,
    judgeScore,
    errors,
  };

  // Store perturbation type as metadata in errors for tracking
  if (perturbation) {
    session = { ...session, errors: [...session.errors, `perturbation:${perturbation.type}`] };
  }

  persistSession(session, batchId, cohortSize);
  persistActionRecords(session.runId, actionRecords);
  return session;
}

function buildToolArgs(toolName: string, user: CohortUser, scenarioId: string): Record<string, unknown> {
  const entity = "Anthropic";
  switch (toolName) {
    case "check_mcp_setup":
      return {};
    case "recon_entity":
      return { entity, scope: scenarioId };
    case "extract_variables":
      return { text: `${entity} analysis for ${user.role} — scenario ${scenarioId}` };
    case "build_claim_graph":
      return { variables: `${entity} key metrics, funding, headcount, product roadmap` };
    case "generate_countermodels":
      return { claimGraph: `${entity} competitive position claim graph` };
    case "rank_interventions":
      return { claimGraph: `${entity} interventions for ${scenarioId}` };
    case "render_decision_memo":
      return {
        interventions: `Top interventions for ${entity}`,
        context: `${user.role} perspective on ${entity} — ${scenarioId}`,
      };
    case "record_event":
      return {
        eventType: `longitudinal.${scenarioId}`,
        actorType: "system",
        entityId: entity.toLowerCase(),
        entityType: "company",
        summary: `Longitudinal harness: ${user.role} ran ${scenarioId} (session ${user.userId})`,
      };
    case "track_milestone":
      return {
        title: `${scenarioId} completed by ${user.role}`,
        category: "longitudinal_benchmark",
      };
    default:
      return {};
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// Metric Computation
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Repeated Cognition Avoided (RCA): % of sessions where the user did NOT
 * restate context or re-ask old questions.
 */
export function computeRCA(sessions: SessionRun[]): number {
  if (sessions.length === 0) return 0;
  const avoided = sessions.filter((s) => !s.contextRestated && !s.repeatQuestionDetected).length;
  return (avoided / sessions.length) * 100;
}

/**
 * Packet Reuse Rate (PRR): % of sessions where a prior packet was reused
 * rather than regenerated from scratch.
 */
export function computePRR(sessions: SessionRun[]): number {
  if (sessions.length === 0) return 0;
  const reused = sessions.filter((s) => s.packetReused).length;
  return (reused / sessions.length) * 100;
}

/**
 * Aggregate all metrics from a batch of sessions into a CohortReport.
 */
export function generateCohortReport(
  sessions: SessionRun[],
  cohortSize: number,
  layer: "n1" | "n5" | "n10" | "n100" | "n1000",
): CohortReport {
  const rca = computeRCA(sessions);
  const prr = computePRR(sessions);

  const roles = [...new Set(sessions.map((s) => s.role))];
  const scenarios = [...new Set(sessions.map((s) => s.scenarioId))];

  // Important-change precision: for sessions running "important_change",
  // how many had no errors (simulated precision).
  const importantChangeSessions = sessions.filter((s) => s.scenarioId === "important_change");
  const importantChangePrecision = importantChangeSessions.length > 0
    ? (importantChangeSessions.filter((s) => s.errors.length === 0).length / importantChangeSessions.length) * 100
    : 100;

  // Contradiction precision: simulated as % of sessions with judgeScore >= 3
  const contradictionSessions = sessions.filter((s) => s.judgeScore >= 3);
  const contradictionPrecision = sessions.length > 0
    ? (contradictionSessions.length / sessions.length) * 100
    : 100;

  // False alert rate: inverse of contradiction precision, floored at 0
  const falseAlertRate = Math.max(0, 100 - contradictionPrecision);

  // Export-to-action rate: % of sessions that produced an export
  const exportToActionRate = sessions.length > 0
    ? (sessions.filter((s) => s.exportProduced).length / sessions.length) * 100
    : 0;

  // Find recurring root cause: most common error prefix
  const errorCounts: Record<string, number> = {};
  for (const s of sessions) {
    for (const e of s.errors) {
      const prefix = e.split(":")[0];
      errorCounts[prefix] = (errorCounts[prefix] ?? 0) + 1;
    }
  }
  const sortedErrors = Object.entries(errorCounts).sort((a, b) => b[1] - a[1]);
  const topRecurringRootCause = sortedErrors.length > 0
    ? `${sortedErrors[0][0]} (${sortedErrors[0][1]} occurrences)`
    : "none";

  // Regression risk: scenarios with lowest avg judge score
  const scenarioScores: Record<string, number[]> = {};
  for (const s of sessions) {
    if (!scenarioScores[s.scenarioId]) scenarioScores[s.scenarioId] = [];
    scenarioScores[s.scenarioId].push(s.judgeScore);
  }
  const scenarioAvgs = Object.entries(scenarioScores).map(([id, scores]) => ({
    id,
    avg: scores.reduce((a, b) => a + b, 0) / scores.length,
  })).sort((a, b) => a.avg - b.avg);
  const topRegressionRisk = scenarioAvgs.length > 0
    ? `${scenarioAvgs[0].id} (avg ${scenarioAvgs[0].avg.toFixed(1)}/5)`
    : "none";

  // Pass/fail evaluation
  const thresholds = PASS_THRESHOLDS[layer];
  let passed = true;
  if (layer === "n1") {
    const avgScore = sessions.length > 0
      ? sessions.reduce((a, s) => a + s.judgeScore, 0) / sessions.length
      : 0;
    passed = avgScore >= thresholds.judgeScore;
  } else {
    if (rca < (thresholds.rca ?? 0)) passed = false;
    if (prr < (thresholds.prr ?? 0)) passed = false;
  }

  return {
    cohortSize,
    totalSessions: sessions.length,
    rolesCovered: roles,
    coreLoopsCovered: scenarios.length,
    repeatedCognitionAvoided: Math.round(rca * 10) / 10,
    packetReuseRate: Math.round(prr * 10) / 10,
    importantChangePrecision: Math.round(importantChangePrecision * 10) / 10,
    contradictionPrecision: Math.round(contradictionPrecision * 10) / 10,
    falseAlertRate: Math.round(falseAlertRate * 10) / 10,
    exportToActionRate: Math.round(exportToActionRate * 10) / 10,
    topRecurringRootCause,
    topRegressionRisk,
    passed,
    passThresholds: thresholds,
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// Drift Durability Score
// ═══════════════════════════════════════════════════════════════════════════

export function computeDriftMetrics(sessions: SessionRun[]): DriftMetrics {
  const perturbedSessions = sessions.filter((s) =>
    s.errors.some((e) => e.startsWith("perturbation:")),
  );
  const cleanSessions = sessions.filter((s) =>
    !s.errors.some((e) => e.startsWith("perturbation:")),
  );

  if (perturbedSessions.length === 0) {
    return { driftRecoveryRate: 100, perturbationSurvivalRate: 100, staleMemoryRejectionRate: 100 };
  }

  // driftRecoveryRate: % of perturbed sessions that still completed (have tool calls and judge >= 2)
  const recovered = perturbedSessions.filter(
    (s) => s.toolCallCount > 0 && s.judgeScore >= 2.0,
  ).length;
  const driftRecoveryRate = (recovered / perturbedSessions.length) * 100;

  // perturbationSurvivalRate: % of perturbations that didn't cause failure (judgeScore >= 3.0)
  const survived = perturbedSessions.filter((s) => s.judgeScore >= 3.0).length;
  const perturbationSurvivalRate = (survived / perturbedSessions.length) * 100;

  // staleMemoryRejectionRate: % of stale_memory perturbations where stale data didn't pollute
  // (judgeScore didn't drop below clean baseline average minus 0.5)
  const cleanAvg = cleanSessions.length > 0
    ? cleanSessions.reduce((a, s) => a + s.judgeScore, 0) / cleanSessions.length
    : 3.5;
  const staleSessions = perturbedSessions.filter((s) =>
    s.errors.some((e) => e.includes("stale_memory")),
  );
  const staleRejected = staleSessions.filter((s) => s.judgeScore >= cleanAvg - 0.5).length;
  const staleMemoryRejectionRate = staleSessions.length > 0
    ? (staleRejected / staleSessions.length) * 100
    : 100;

  return { driftRecoveryRate, perturbationSurvivalRate, staleMemoryRejectionRate };
}

// ═══════════════════════════════════════════════════════════════════════════
// Composite Durability Score
// ═══════════════════════════════════════════════════════════════════════════

export function computeDurabilityScore(sessions: SessionRun[]): DurabilityScore {
  if (sessions.length === 0) {
    return { composite: 0, completionStability: 0, rerunSavings: 0, artifactQuality: 0, memoryUsefulness: 0, driftResistance: 0, crossSessionContinuity: 0 };
  }

  // completionStability (25%): completion rate across all sessions (judge >= 2.0)
  const completed = sessions.filter((s) => s.toolCallCount > 0 && s.judgeScore >= 2.0).length;
  const completionStability = (completed / sessions.length) * 100;

  // rerunSavings (20%): % of sessions with packet reuse (PRR)
  const rerunSavings = computePRR(sessions);

  // artifactQuality (20%): average judge score / 5.0 * 100
  const avgJudge = sessions.reduce((a, s) => a + s.judgeScore, 0) / sessions.length;
  const artifactQuality = (avgJudge / 5.0) * 100;

  // memoryUsefulness (15%): RCA * (1 - staleMemoryPollutionRate)
  const rca = computeRCA(sessions);
  const drift = computeDriftMetrics(sessions);
  const staleMemoryPollutionRate = 1 - drift.staleMemoryRejectionRate / 100;
  const memoryUsefulness = (rca / 100) * (1 - staleMemoryPollutionRate) * 100;

  // driftResistance (10%): perturbation survival rate
  const driftResistance = drift.perturbationSurvivalRate;

  // crossSessionContinuity (10%): % of multi-session users with context carryover
  const userSessions: Record<string, SessionRun[]> = {};
  for (const s of sessions) {
    if (!userSessions[s.userId]) userSessions[s.userId] = [];
    userSessions[s.userId].push(s);
  }
  const multiSessionUsers = Object.values(userSessions).filter((us) => us.length > 1);
  let continuityCount = 0;
  for (const us of multiSessionUsers) {
    const laterSessions = us.filter((s) => s.sessionIndex > 1);
    const hasCarryover = laterSessions.some((s) => !s.contextRestated);
    if (hasCarryover) continuityCount++;
  }
  const crossSessionContinuity = multiSessionUsers.length > 0
    ? (continuityCount / multiSessionUsers.length) * 100
    : 0;

  // Weighted composite
  const composite = Math.round(
    completionStability * 0.25 +
    rerunSavings * 0.20 +
    artifactQuality * 0.20 +
    memoryUsefulness * 0.15 +
    driftResistance * 0.10 +
    crossSessionContinuity * 0.10,
  );

  return {
    composite: Math.max(0, Math.min(100, composite)),
    completionStability: Math.round(completionStability * 10) / 10,
    rerunSavings: Math.round(rerunSavings * 10) / 10,
    artifactQuality: Math.round(artifactQuality * 10) / 10,
    memoryUsefulness: Math.round(memoryUsefulness * 10) / 10,
    driftResistance: Math.round(driftResistance * 10) / 10,
    crossSessionContinuity: Math.round(crossSessionContinuity * 10) / 10,
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// Period Rollups
// ═══════════════════════════════════════════════════════════════════════════

export function computeRollup(
  sessions: SessionRun[],
  period: "daily" | "weekly" | "monthly",
): PeriodRollup[] {
  const now = new Date();
  const keyFn = (d: Date): string => {
    switch (period) {
      case "daily":
        return d.toISOString().slice(0, 10); // 2026-03-24
      case "weekly": {
        const jan1 = new Date(d.getFullYear(), 0, 1);
        const weekNum = Math.ceil(((d.getTime() - jan1.getTime()) / 86400000 + jan1.getDay() + 1) / 7);
        return `${d.getFullYear()}-W${String(weekNum).padStart(2, "0")}`;
      }
      case "monthly":
        return d.toISOString().slice(0, 7); // 2026-03
    }
  };

  // For simulation, all sessions are "today" — group them under current period
  const periodKey = keyFn(now);
  if (sessions.length === 0) return [];

  const completedCount = sessions.filter((s) => s.toolCallCount > 0 && s.judgeScore >= 2.0).length;
  const completionRate = (completedCount / sessions.length) * 100;
  const avgJudgeScore = sessions.reduce((a, s) => a + s.judgeScore, 0) / sessions.length;
  const rca = computeRCA(sessions);
  const prr = computePRR(sessions);
  const durability = computeDurabilityScore(sessions);

  // Top failure mode
  const errorCounts: Record<string, number> = {};
  for (const s of sessions) {
    for (const e of s.errors) {
      const prefix = e.split(":")[0];
      errorCounts[prefix] = (errorCounts[prefix] ?? 0) + 1;
    }
  }
  const sorted = Object.entries(errorCounts).sort((a, b) => b[1] - a[1]);
  const topFailureMode = sorted.length > 0 ? `${sorted[0][0]}(${sorted[0][1]})` : "none";

  const rollup: PeriodRollup = {
    period,
    periodKey,
    totalRuns: sessions.length,
    completionRate: Math.round(completionRate * 10) / 10,
    avgJudgeScore: Math.round(avgJudgeScore * 100) / 100,
    rca: Math.round(rca * 10) / 10,
    prr: Math.round(prr * 10) / 10,
    durabilityScore: durability.composite,
    topFailureMode,
    createdAt: now.toISOString(),
  };

  // Persist
  const db = getDb();
  db.prepare(`
    INSERT OR REPLACE INTO benchmark_rollups (period, periodKey, totalRuns, completionRate, avgJudgeScore, rca, prr, durabilityScore, topFailureMode, createdAt)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(rollup.period, rollup.periodKey, rollup.totalRuns, rollup.completionRate, rollup.avgJudgeScore, rollup.rca, rollup.prr, rollup.durabilityScore, rollup.topFailureMode, rollup.createdAt);

  return [rollup];
}

// ═══════════════════════════════════════════════════════════════════════════
// Maturity Levels
// ═══════════════════════════════════════════════════════════════════════════

export function computeMaturityLevel(
  scenarioId: string,
  sessions: SessionRun[],
  batchId: string,
): MaturityAssessment {
  const scenarioSessions = sessions.filter((s) => s.scenarioId === scenarioId);
  const n = scenarioSessions.length;
  const scores = scenarioSessions.map((s) => s.judgeScore);
  const avg = n > 0 ? scores.reduce((a, b) => a + b, 0) / n : 0;
  const variance = n > 1
    ? scores.reduce((a, s) => a + Math.pow(s - avg, 2), 0) / (n - 1)
    : 0;
  const coeffVar = avg > 0 ? (Math.sqrt(variance) / avg) * 100 : 100;

  const prr = computePRR(scenarioSessions);
  const rca = computeRCA(scenarioSessions);
  const drift = computeDriftMetrics(scenarioSessions);
  const durability = computeDurabilityScore(scenarioSessions);

  let level: MaturityLevel;
  let label: string;
  let evidence: string;

  if (durability.composite > 85 && prr > 80 && rca > 90 && n >= 30) {
    level = "E";
    label = "institutional";
    evidence = `PRR=${prr.toFixed(0)}% RCA=${rca.toFixed(0)}% durability=${durability.composite} n=${n} over 30+ sessions`;
  } else if (n >= 10 && drift.perturbationSurvivalRate > 80 && drift.driftRecoveryRate > 70) {
    level = "D";
    label = "durable";
    evidence = `pertSurvival=${drift.perturbationSurvivalRate.toFixed(0)}% driftRecovery=${drift.driftRecoveryRate.toFixed(0)}% n=${n}`;
  } else if (n >= 10 && prr > 0 && drift.perturbationSurvivalRate > 80) {
    level = "C";
    label = "hardened";
    evidence = `PRR=${prr.toFixed(0)}% pertSurvival=${drift.perturbationSurvivalRate.toFixed(0)}% n=${n}`;
  } else if (n >= 5 && coeffVar < 20) {
    level = "B";
    label = "stable";
    evidence = `CV=${coeffVar.toFixed(1)}% avg=${avg.toFixed(2)} n=${n}`;
  } else if (n >= 1 && avg >= 2.0) {
    level = "A";
    label = "smoke-ready";
    evidence = `avg=${avg.toFixed(2)} n=${n}`;
  } else {
    level = "A";
    label = "smoke-ready (marginal)";
    evidence = `avg=${avg.toFixed(2)} n=${n} — below smoke threshold`;
  }

  // Persist
  const db = getDb();
  db.prepare(`
    INSERT OR REPLACE INTO workflow_maturity (scenarioId, maturityLevel, label, evidence, batchId)
    VALUES (?, ?, ?, ?, ?)
  `).run(scenarioId, level, label, evidence, batchId);

  return { level, label, scenarioId, evidence };
}

// ═══════════════════════════════════════════════════════════════════════════
// N-level Runners
// ═══════════════════════════════════════════════════════════════════════════

/**
 * N=1: Single golden-path founder run.
 * Validates that the core tool chain works end-to-end for one scenario.
 */
export async function runN1(): Promise<{ session: SessionRun; report: CohortReport }> {
  const batchId = genId("batch");
  const user = COHORT_USERS[0]; // founder
  const scenario = user.typicalScenarios[0]; // weekly_reset
  console.log(`\n=== N=1: Golden Path — ${user.role} / ${scenario} ===\n`);

  const session = await simulateSession(user, scenario, 1, "same_session", batchId, 1);
  const report = generateCohortReport([session], 1, "n1");

  printSessionLine(session);
  printReport(report, "N=1");
  return { session, report };
}

/**
 * N=5: 5 users (founder, banker, ceo, researcher, student), 1 session each.
 * All against the same entity "Anthropic".
 */
export async function runN5(): Promise<CohortReport> {
  const batchId = genId("batch");
  const users = COHORT_USERS.slice(0, 5);
  console.log(`\n=== N=5: Role Generalization — ${users.map((u) => u.role).join(", ")} ===\n`);

  const sessions: SessionRun[] = [];
  for (const user of users) {
    const scenario = user.typicalScenarios[0];
    const session = await simulateSession(user, scenario, 1, "same_session", batchId, 5);
    sessions.push(session);
    printSessionLine(session);
  }

  const report = generateCohortReport(sessions, 5, "n5");
  printReport(report, "N=5");
  return report;
}

/**
 * N=10: 5 users x 2 sessions. Sessions 6-10 receive perturbations.
 * Tests session-continuity and drift resistance.
 */
export async function runN10(): Promise<CohortReport> {
  const batchId = genId("batch");
  const users = COHORT_USERS.slice(0, 5);
  console.log(`\n=== N=10: Session Continuity + Perturbations — 5 users x 2 sessions ===\n`);
  console.log(`  Sessions 1-5: clean baseline | Sessions 6-10: perturbed\n`);

  const sessions: SessionRun[] = [];
  let globalIdx = 0;
  for (const user of users) {
    for (let sessionIdx = 1; sessionIdx <= 2; sessionIdx++) {
      globalIdx++;
      const scenario = user.typicalScenarios[(sessionIdx - 1) % user.typicalScenarios.length];
      const horizon: SessionRun["timeHorizon"] = sessionIdx === 1 ? "same_session" : "next_day";
      // Apply perturbation to sessions 6-10
      const perturbation = globalIdx > 5 ? selectPerturbation(globalIdx) : undefined;
      const session = await simulateSession(user, scenario, sessionIdx, horizon, batchId, 10, perturbation);
      sessions.push(session);
      printSessionLine(session, perturbation);
    }
  }

  const report = generateCohortReport(sessions, 10, "n10");
  const drift = computeDriftMetrics(sessions);
  const durability = computeDurabilityScore(sessions);
  const rollups = computeRollup(sessions, "daily");

  // Compute maturity per scenario
  const scenarios = [...new Set(sessions.map((s) => s.scenarioId))];
  const maturityAssessments = scenarios.map((sc) => computeMaturityLevel(sc, sessions, batchId));

  printReport(report, "N=10");
  printDurabilityReport(durability, drift);
  printMaturityReport(maturityAssessments);
  if (rollups.length > 0) printRollupSummary(rollups);
  return report;
}

/**
 * N=100: 10 users x 10 sessions each (simulated across time horizons).
 * Sessions 1-20: clean baseline. Sessions 21-100: perturbed.
 * Measures RCA + PRR compounding over time + drift durability.
 */
export async function runN100(): Promise<CohortReport> {
  const batchId = genId("batch");
  console.log(`\n=== N=100: Longitudinal Compounding — 10 users x 10 sessions ===\n`);
  console.log(`  Sessions 1-20: clean baseline | Sessions 21-100: perturbed\n`);

  const sessions: SessionRun[] = [];
  let globalIdx = 0;
  for (const user of COHORT_USERS) {
    for (let sessionIdx = 1; sessionIdx <= 10; sessionIdx++) {
      globalIdx++;
      const scenario = user.typicalScenarios[(sessionIdx - 1) % user.typicalScenarios.length];
      // Spread sessions across time horizons to simulate real usage patterns
      const horizonIdx = Math.min(sessionIdx - 1, TIME_HORIZONS.length - 1);
      const horizon = TIME_HORIZONS[horizonIdx];
      // Apply perturbation to sessions 21-100
      const perturbation = globalIdx > 20 ? selectPerturbation(globalIdx) : undefined;
      const session = await simulateSession(user, scenario, sessionIdx, horizon, batchId, 100, perturbation);
      sessions.push(session);
      printSessionLine(session, perturbation);
    }
  }

  const report = generateCohortReport(sessions, 100, "n100");
  const drift = computeDriftMetrics(sessions);
  const durability = computeDurabilityScore(sessions);

  // Rollups for all periods
  const dailyRollups = computeRollup(sessions, "daily");
  const weeklyRollups = computeRollup(sessions, "weekly");
  const monthlyRollups = computeRollup(sessions, "monthly");

  // Compute maturity per scenario
  const scenarios = [...new Set(sessions.map((s) => s.scenarioId))];
  const maturityAssessments = scenarios.map((sc) => computeMaturityLevel(sc, sessions, batchId));

  printReport(report, "N=100");
  printDurabilityReport(durability, drift);
  printMaturityReport(maturityAssessments);
  printRollupSummary([...dailyRollups, ...weeklyRollups, ...monthlyRollups]);
  return report;
}

// ═══════════════════════════════════════════════════════════════════════════
// N=1000 Compaction Resilience Simulation
// ═══════════════════════════════════════════════════════════════════════════

export interface CompactionMetrics {
  compactionRecoveryRate: number;
  memoryDecayRate: number;
  intentPreservationRate: number;
  compactionEvents: number;
  postCompactionRecoveries: number;
  staleMemoryErrors: number;
  lostIntents: number;
}

/**
 * Simulate a compaction event: clear old causal_events, record a session summary,
 * and check if the next session can recover context.
 */
function simulateCompaction(
  db: ReturnType<typeof getDb>,
  userId: string,
  currentSessionIndex: number,
  cutoffAge: number,
): { cleared: number; summaryRecorded: boolean } {
  // Clear causal_events older than cutoffAge sessions ago
  const cutoffSession = currentSessionIndex - cutoffAge;
  const deleteResult = db.prepare(`
    DELETE FROM causal_events
    WHERE userId = ?
    AND json_extract(payload, '$.sessionIndex') < ?
  `).run(userId, cutoffSession);

  const cleared = typeof deleteResult.changes === "number" ? deleteResult.changes : 0;

  // Record a compaction summary (simulated session_summaries entry)
  db.prepare(`
    INSERT OR IGNORE INTO causal_events (id, userId, eventType, payload)
    VALUES (?, ?, ?, ?)
  `).run(
    genId("compact"),
    userId,
    "compaction_summary",
    JSON.stringify({
      sessionIndex: currentSessionIndex,
      clearedEvents: cleared,
      cutoffSession,
      timestamp: Date.now(),
    }),
  );

  return { cleared, summaryRecorded: true };
}

/**
 * Check whether a user can recover context after a compaction event.
 * Recovery means there is at least one causal event (compaction_summary or recent session_start).
 */
function canRecoverAfterCompaction(db: ReturnType<typeof getDb>, userId: string): boolean {
  const row = db.prepare(`
    SELECT COUNT(*) as c FROM causal_events
    WHERE userId = ?
    AND (eventType = 'compaction_summary' OR eventType = 'session_start')
  `).get(userId) as { c: number } | undefined;
  return (row?.c ?? 0) > 0;
}

/**
 * N=1000: 10 users x 100 sessions each.
 * - Sessions 1-50: clean baseline
 * - Sessions 51-1000: perturbed
 * - Every 100th session: compaction event (clear old causal_events, record summary)
 * - New metrics: compactionRecoveryRate, memoryDecayRate, intentPreservationRate
 *
 * Pass thresholds: RCA >= 80%, PRR >= 60%, compactionRecoveryRate >= 70%
 */
export async function runN1000(): Promise<CohortReport & { compaction: CompactionMetrics }> {
  const batchId = genId("batch");
  console.log(`\n=== N=1000: Compaction Resilience — 10 users x 100 sessions ===\n`);
  console.log(`  Sessions 1-50: clean baseline | Sessions 51-1000: perturbed`);
  console.log(`  Every 100th session: compaction event\n`);

  const sessions: SessionRun[] = [];
  const db = getDb();

  // Compaction tracking
  let compactionEvents = 0;
  let postCompactionRecoveries = 0;
  let postCompactionAttempts = 0;
  let staleMemoryErrors = 0;
  let totalActiveIntents = 0;
  let survivedIntents = 0;

  let globalIdx = 0;
  for (const user of COHORT_USERS) {
    let lastWasCompaction = false;

    for (let sessionIdx = 1; sessionIdx <= 100; sessionIdx++) {
      globalIdx++;
      const scenario = user.typicalScenarios[(sessionIdx - 1) % user.typicalScenarios.length];
      const horizonIdx = Math.min(sessionIdx - 1, TIME_HORIZONS.length - 1);
      const horizon = TIME_HORIZONS[horizonIdx % TIME_HORIZONS.length];

      // Compaction event every 100th global session
      if (globalIdx % 100 === 0) {
        simulateCompaction(db, user.userId, sessionIdx, 50);
        compactionEvents++;
        lastWasCompaction = true;
      }

      // Check post-compaction recovery on the session right after compaction
      if (lastWasCompaction && globalIdx % 100 === 1) {
        postCompactionAttempts++;
        if (canRecoverAfterCompaction(db, user.userId)) {
          postCompactionRecoveries++;
        }
        lastWasCompaction = false;
      }

      // Apply perturbation to sessions 51+ (first 50 are clean baseline)
      const perturbation = globalIdx > 50 ? selectPerturbation(globalIdx) : undefined;
      const session = await simulateSession(user, scenario, sessionIdx, horizon, batchId, 1000, perturbation);
      sessions.push(session);

      // Track stale memory errors
      if (session.errors.some((e) => e.includes("stale") || e.includes("memory"))) {
        staleMemoryErrors++;
      }

      // Track intent preservation: if the session has context restated, an intent was "lost"
      totalActiveIntents++;
      if (!session.contextRestated) {
        survivedIntents++;
      }

      // Print progress every 100 sessions
      if (globalIdx % 100 === 0) {
        const rca = computeRCA(sessions);
        const prr = computePRR(sessions);
        console.log(
          `  [${String(globalIdx).padStart(4)}/1000] ` +
          `RCA=${rca.toFixed(1)}% PRR=${prr.toFixed(1)}% ` +
          `compactions=${compactionEvents} ` +
          `recoveries=${postCompactionRecoveries}/${postCompactionAttempts}`,
        );
      }
    }
  }

  // Handle edge case: first post-compaction session in the sequence
  // The very last compaction at session 1000 won't have a follow-up in-loop,
  // so do one final recovery check per user
  for (const user of COHORT_USERS) {
    if (canRecoverAfterCompaction(db, user.userId)) {
      // Already counted above — skip double-counting
    }
  }

  const compactionRecoveryRate = postCompactionAttempts > 0
    ? (postCompactionRecoveries / postCompactionAttempts) * 100
    : 100;
  const memoryDecayRate = sessions.length > 0
    ? (staleMemoryErrors / sessions.length) * 100
    : 0;
  const intentPreservationRate = totalActiveIntents > 0
    ? (survivedIntents / totalActiveIntents) * 100
    : 100;

  const compaction: CompactionMetrics = {
    compactionRecoveryRate: Math.round(compactionRecoveryRate * 10) / 10,
    memoryDecayRate: Math.round(memoryDecayRate * 10) / 10,
    intentPreservationRate: Math.round(intentPreservationRate * 10) / 10,
    compactionEvents,
    postCompactionRecoveries,
    staleMemoryErrors,
    lostIntents: totalActiveIntents - survivedIntents,
  };

  const report = generateCohortReport(sessions, 1000, "n1000");

  // Override pass/fail to include compaction threshold
  const compactionThreshold = PASS_THRESHOLDS.n1000.compactionRecoveryRate ?? 70;
  const passed = report.passed && compactionRecoveryRate >= compactionThreshold;

  const drift = computeDriftMetrics(sessions);
  const durability = computeDurabilityScore(sessions);
  const dailyRollups = computeRollup(sessions, "daily");
  const weeklyRollups = computeRollup(sessions, "weekly");
  const monthlyRollups = computeRollup(sessions, "monthly");
  const scenarios = [...new Set(sessions.map((s) => s.scenarioId))];
  const maturityAssessments = scenarios.map((sc) => computeMaturityLevel(sc, sessions, batchId));

  printReport({ ...report, passed }, "N=1000");
  printCompactionReport(compaction);
  printDurabilityReport(durability, drift);
  printMaturityReport(maturityAssessments);
  printRollupSummary([...dailyRollups, ...weeklyRollups, ...monthlyRollups]);

  return { ...report, passed, compaction };
}

function printCompactionReport(c: CompactionMetrics): void {
  console.log(`
╔══════════════════════════════════════════════════════════════╗
║  COMPACTION RESILIENCE                                       ║
╠══════════════════════════════════════════════════════════════╣
║  Compaction events:           ${String(c.compactionEvents).padStart(6)}                       ║
║  Post-compaction recoveries:  ${String(c.postCompactionRecoveries).padStart(6)}                       ║
║  Compaction Recovery Rate:    ${String(c.compactionRecoveryRate).padStart(6)}%                ║
║  Memory Decay Rate:           ${String(c.memoryDecayRate).padStart(6)}%                ║
║  Intent Preservation Rate:    ${String(c.intentPreservationRate).padStart(6)}%                ║
║  Stale memory errors:         ${String(c.staleMemoryErrors).padStart(6)}                       ║
║  Lost intents:                ${String(c.lostIntents).padStart(6)}                       ║
╚══════════════════════════════════════════════════════════════╝
`);
}

// ═══════════════════════════════════════════════════════════════════════════
// Output Formatting
// ═══════════════════════════════════════════════════════════════════════════

function printSessionLine(s: SessionRun, perturbation?: Perturbation): void {
  const realErrors = s.errors.filter((e) => !e.startsWith("perturbation:"));
  const status = realErrors.length === 0 ? "OK" : `ERR(${realErrors.length})`;
  const reuse = s.packetReused ? "REUSE" : s.packetGenerated ? "NEW" : "NONE";
  const restated = s.contextRestated ? "RESTATED" : "FRESH";
  const pertMarker = perturbation ? ` [PERTURB:${perturbation.type}/${perturbation.severity}]` : "";
  console.log(
    `  [${s.role.padEnd(10)}] sess=${s.sessionIndex} ${s.scenarioId.padEnd(18)} ` +
    `tools=${s.toolCallCount} ${s.latencyMs}ms judge=${s.judgeScore.toFixed(1)} ` +
    `packet=${reuse} ctx=${restated} ${status}${pertMarker}`,
  );
}

